// Provide a deterministic style-enriched item for manual testing.
return [{
  json: {
    id: 'manual:https://example.com/ai-agent',
    source: 'manual',
    title: 'AI Agent 與工作流',
    url: 'https://example.com/ai-agent',
    language: 'zh-TW',
    content: 'AI Agent 不應只負責生成文字，也應根據工具結果規劃下一步。',
    score: 85,
    shouldWrite: true,
    analysis: {
      topic: 'AI Agent',
      coreIdea: 'AI Agent 應根據工具結果規劃下一步',
      audience: 'n8n 與自動化使用者',
      angles: ['Agent orchestration', 'Tool use'],
      keywords: ['AI Agent', 'n8n', 'workflow automation'],
      researchQuestions: ['什麼是 AI Agent？'],
      riskNotes: []
    },
    research: {
      query: 'AI Agent workflow automation',
      sources: [
        {
          title: '人工智慧代理',
          url: 'https://zh.wikipedia.org/wiki/...',
          excerpt: 'AI Agent 會感知環境並採取行動。'
        }
      ],
      sourceCount: 1,
      notes: 'Verify time-sensitive claims against official sources.'
    },
    styleRag: {
      query: 'AI Agent',
      model: 'nvidia/llama-nemotron-embed-1b-v2',
      collection: 'medium_style_chunks_v2',
      matches: [
        {
          id: 'sample-1',
          score: 0.82,
          title: '過去文章範例',
          url: 'https://medium.com/@example/sample',
          text: '我通常會先提出一個具體問題，再逐步拆解背後的機制與可行做法。',
          section: 'chunk-1',
          styleTags: ['question-opening', 'short-paragraphs']
        }
      ],
      matchCount: 1
    },
    metadata: {
      status: 'style_retrieved'
    }
  }
}];

// Build a constrained long-form writing prompt from content, research, and style examples.
const input = $input.first().json;
const body = input.body ?? input;

if (!body.shouldWrite) {
  throw new Error('Input content is not approved for writing');
}
if (!body.analysis?.topic || !body.analysis?.coreIdea) {
  throw new Error('analysis.topic and analysis.coreIdea are required');
}

const styleExamples = (body.styleRag?.matches ?? [])
  .slice(0, 6)
  .map((match, index) => ({
    index: index + 1,
    title: match.title,
    excerpt: match.text,
    styleTags: match.styleTags ?? []
  }));

const researchSources = (body.research?.sources ?? [])
  .slice(0, 6)
  .map((source, index) => ({
    index: index + 1,
    title: source.title,
    url: source.url,
    excerpt: source.excerpt
  }));

const systemPrompt = `你是 Phoenix AI Content Engine 的繁體中文長文作者。你的任務是把短內容重組為 Medium 深度文章。你必須遵守以下規則：

1. 文章使用繁體中文。
2. 不要聲稱自己就是原作者，也不要聲稱百分之百複製某位作者。
3. 可參考歷史文章的節奏、段落長度、開場方式與論證方式，但不得大段複製歷史文章。
4. 不得捏造來源、數據、人物、日期或引用。
5. 若研究資料不足，明確使用保守語氣，不要硬補事實。
6. 文章需要有清楚的標題、導言、至少三個主段落、具體案例或實作建議、結論與 CTA。
7. 輸出只能是合法 JSON，不要使用 Markdown code fence。

輸出格式：
{
  "title": "文章標題",
  "subtitle": "副標題",
  "summary": "120 字內摘要",
  "tags": ["標籤"],
  "markdown": "# 標題\n\n完整文章",
  "wordCountEstimate": 0
}`;

const userPrompt = JSON.stringify({
  task: '將以下內容重製為 1800 至 3000 字的 Medium 深度長文',
  original: {
    title: body.title,
    url: body.url,
    content: body.content
  },
  analysis: body.analysis,
  research: {
    sources: researchSources,
    notes: body.research?.notes ?? ''
  },
  styleContext: {
    examples: styleExamples,
    instruction: '只學習文風特徵，不得複製原句。'
  }
});

return [{
  json: {
    original: body,
    systemPrompt,
    userPrompt
  }
}];

