// Parse and validate the OpenRouter writer response.
const response = $input.first().json;
const original = $('BuildWriterPrompt').first().json.original;
const statusCode = response.statusCode ?? 0;
const raw = response.body?.choices?.[0]?.message?.content ?? '';

let draft = null;
let parseError = null;

try {
  draft = JSON.parse(String(raw).replace(/^```json\s*|\s*```$/g, '').trim());
} catch (error) {
  parseError = error.message;
}

const valid = statusCode >= 200 &&
  statusCode < 300 &&
  draft &&
  typeof draft.title === 'string' &&
  typeof draft.markdown === 'string' &&
  draft.markdown.length >= 500;

return [{
  json: {
    original,
    provider: 'openrouter',
    statusCode,
    raw,
    draft,
    valid,
    fallbackRequired: !valid,
    error: parseError
  }
}];

