// Parse and validate the NVIDIA fallback draft.
const response = $input.first().json;
const original = $('BuildWriterPrompt').first().json.original;
const statusCode = response.statusCode ?? 0;
const raw = response.body?.choices?.[0]?.message?.content ?? '';

let draft;
try {
  draft = JSON.parse(String(raw).replace(/^```json\s*|\s*```$/g, '').trim());
} catch (error) {
  throw new Error(`NVIDIA writer response is not valid JSON: ${error.message}`);
}

if (!(statusCode >= 200 && statusCode < 300)) {
  throw new Error(`NVIDIA writer request failed with status ${statusCode}`);
}

if (typeof draft.title !== 'string' || typeof draft.markdown !== 'string' || draft.markdown.length < 500) {
  throw new Error('NVIDIA writer response is missing title or a sufficiently long markdown draft');
}

return [{
  json: {
    original,
    provider: 'nvidia',
    draft
  }
}];

// Normalize the selected draft into the Phoenix article contract.
const input = $input.first().json;
const original = input.original;
const draft = input.draft;

const markdown = String(draft.markdown ?? '').trim();
const tags = Array.isArray(draft.tags)
  ? draft.tags.map((tag) => String(tag).trim()).filter(Boolean).slice(0, 5)
  : [];

return [{
  json: {
    ...original,
    article: {
      title: String(draft.title ?? '').trim(),
      subtitle: String(draft.subtitle ?? '').trim(),
      summary: String(draft.summary ?? '').trim(),
      tags,
      markdown,
      wordCountEstimate: Number(draft.wordCountEstimate ?? markdown.length)
    },
    metadata: {
      ...original.metadata,
      writer: '06-writer-agent',
      writerVersion: '0.6.0',
      provider: input.provider,
      status: 'drafted',
      draftedAt: new Date().toISOString()
    }
  }
}];
